mapper.update:
UPDATE chat_contact
SET last_read_id = last_msg_id
WHERE room_id = #{roomId}
  AND user_id = #{userId}
  AND (last_read_id IS NULL OR last_msg_id IS NOT NULL AND last_read_id < last_msg_id)

mapper.select:
SELECT c.*,
       COALESCE(
               (SELECT COUNT(*) FROM chat_message m
                WHERE m.room_id = c.room_id
                  AND m.is_visible = TRUE
                  AND m.from_uid != #{userId}
        AND (c.last_read_id IS NULL OR m.id > c.last_read_id)
     ), 0
   ) AS unread
FROM chat_contact c
WHERE c.user_id = #{userId}
ORDER BY c.top DESC, c.active_time DESC
